function toFiniteNumber(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}
return $input.all().map((item) => {
  const raw = item.json ?? {};
  const hasWrapper = Object.prototype.hasOwnProperty.call(raw, 'statusCode');
  const statusFromWrapper = toFiniteNumber(raw.statusCode);
  const statusFromCanonical = toFiniteNumber(raw.http_status);
  const httpStatus = statusFromWrapper ?? statusFromCanonical ?? (hasWrapper ? 0 : 200);
  const bodyCandidate = hasWrapper ? raw.body : (raw.http_body ?? raw);
  const httpBody = bodyCandidate && typeof bodyCandidate === 'object' ? bodyCandidate : {};
  const httpOk = httpStatus >= 200 && httpStatus < 300;
  const retryable = [429, 500].includes(httpStatus);
  return {
    json: {
      ...raw,
      http_status: httpStatus,
      http_body: httpBody,
      http_ok: httpOk,
