﻿const rows = $input.all().map((item) => item.json ?? {});
const nowIso = new Date().toISOString();

function lower(value) {
  return String(value ?? '').trim().toLowerCase();
}

function toNum(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function uniq(values) {
  return [...new Set(values.filter(Boolean))];
}

function firstNonEmpty(values, fallback = '') {
  for (const v of values) {
    const t = String(v ?? '').trim();
    if (t) return t;
  }
  return fallback;
}

const correlationId = firstNonEmpty(
  rows.map((r) => r.correlation_id),
  `ak-f2-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`
);
const logicalExecutionId = firstNonEmpty(rows.map((r) => r.logical_execution_id), `${correlationId}:f2`);
const executionId = firstNonEmpty(rows.map((r) => r.execution_id), logicalExecutionId);
const executionMode = firstNonEmpty(rows.map((r) => r.run_mode ?? r.execution_mode), 'internal_execute_workflow');
const notification = rows.find((r) => r.notification && typeof r.notification === 'object')?.notification ?? {};

const contractIds = uniq(rows.map((r) => String(r.Contrato_ID ?? '').trim()));
const influencers = uniq(rows.map((r) => String(r.Cliente ?? r.influencer ?? '').trim()));

const preventiveRows = rows.filter((r) => {
  const alertType = lower(r.alert_type);
  const controlType = lower(r.control_type);
  return alertType === 'preventive_48h' || controlType === 'preventive';
});

const expiredUnpausedRows = rows.filter((r) => {
  const alertType = lower(r.alert_type);
  return alertType.startsWith('expired_not_paused') || alertType.includes('expired_not_paused');
});

const preventiveContractIds = uniq(preventiveRows.map((r) => String(r.Contrato_ID ?? '').trim()));
const expiredUnpausedContractIds = uniq(expiredUnpausedRows.map((r) => String(r.Contrato_ID ?? '').trim()));

let adsEvaluated = rows.reduce((acc, r) => acc + toNum(r.ads_total, 0), 0);
if (adsEvaluated === 0) {
  adsEvaluated = preventiveRows.length + expiredUnpausedRows.length;
}

let pausedSuccessCount = rows.reduce((acc, r) => acc + toNum(r.ads_paused, 0), 0);
let pausedErrorCount = rows.reduce((acc, r) => acc + toNum(r.ads_failed, 0), 0);

const incidents = [];
for (const row of rows) {
  if (Array.isArray(row.incidents)) {
    for (const it of row.incidents) {
      incidents.push(it);
    }
  }

  const pauseState = lower(row.pause_state);
  const hasPauseError = pauseState === 'failed' || pauseState === 'list_failed' || pauseState === 'partial';
  if (hasPauseError) {
    incidents.push({
      type: 'pause_failed',
      code: firstNonEmpty([row.pause_reason, row.error_code], 'PAUSE_FAILED'),
      message: firstNonEmpty([row.list_error, row.error_message], `Pause state ${pauseState}`),
      contract_id: String(row.Contrato_ID ?? ''),
      influencer: String(row.Cliente ?? row.influencer ?? '').trim(),
      ad_id: String(row.Ad_ID ?? ''),
      stage: firstNonEmpty([row.error_stage], pauseState)
    });
  }
}

if (expiredUnpausedRows.length > 0 && incidents.length === 0) {
  for (const row of expiredUnpausedRows) {
    incidents.push({
      type: 'expired_not_paused',
      code: firstNonEmpty([row.alert_type], 'EXPIRED_NOT_PAUSED'),
      message: firstNonEmpty([row.message], 'Expired contract has ads not paused'),
      contract_id: String(row.Contrato_ID ?? ''),
      influencer: String(row.Cliente ?? row.influencer ?? '').trim(),
      ad_id: String(row.Ad_ID ?? '')
    });
  }
}

const hasCritical = expiredUnpausedContractIds.length > 0;
const hasWarnSignals = preventiveContractIds.length > 0 || pausedErrorCount > 0 || incidents.length > 0;

const executionStatus = hasCritical || pausedErrorCount > 0 ? 'partial_failure' : 'success';
const severity = hasCritical ? 'CRITICAL' : (hasWarnSignals ? 'WARN' : 'INFO');

const context = {
  contract_ids: contractIds,
  influencers,
  Contrato_ID: contractIds[0] ?? '',
  Ad_ID: '',
  alert_type: hasCritical ? 'EXPIRED_NOT_PAUSED' : (preventiveContractIds.length > 0 ? 'PREVENTIVE_48H' : ''),
  error_stage: '',
  status_contrato: '',
  message: preventiveContractIds.length > 0
    ? `Preventive alerts: ${preventiveContractIds.length} contract(s) in 48h window.`
    : (hasCritical ? 'Critical alerts detected: expired contracts with unpaused ads.' : 'No critical or preventive alerts.'),
  crm_url: firstNonEmpty(rows.map((r) => r.crm_url ?? r.sheet_url ?? r.context?.crm_url ?? r.context?.sheet_url), '')
};

const durationMs = toNum(rows[0]?.duration_ms, 0);

return [{
  json: {
    schema_version: '1.0.0',
    event_type: 'killswitch.execution.summary',
    source_workflow: 'contract-guard-daily-killswitch',
    target_workflow_id: 'BFHHQwYFfmcpqshb',
    timezone: 'America/Argentina/Buenos_Aires',
    correlation_id: correlationId,
    logical_execution_id: logicalExecutionId,
    execution_id: executionId,
    execution_status: executionStatus,
    severity,
    execution_mode: executionMode,
    executed_at: nowIso,
    metrics: {
      contracts_evaluated: contractIds.length,
      ads_evaluated: adsEvaluated,
      paused_success_count: pausedSuccessCount,
      paused_error_count: pausedErrorCount,
      expired_unpaused_count: expiredUnpausedContractIds.length,
      preventive_48h_count: preventiveContractIds.length,
      duration_ms: durationMs
    },
    incidents,
    notification,
    context
  }
}];

const nowIso = $now.setZone('America/Argentina/Buenos_Aires').toISO();

function toFinalStatus(row) {
  const pauseState = String(row.pause_state ?? '').toLowerCase();
  const precheckState = String(row.precheck_state ?? '').toLowerCase();
  const statusContrato = String(row.Status_Contrato ?? '').toLowerCase();

  if (pauseState === 'success' || statusContrato === 'finalizado') return 'paused';
  if (precheckState === 'not_actionable') return 'already_paused';
  if (precheckState === 'failed' || pauseState === 'failed') return 'failed';
  if (['retry', 'ready_to_pause'].includes(precheckState) || pauseState === 'retry') return 'processing';
  return 'processing';
}

return $input.all().flatMap((item) => {
  const row = item.json ?? {};
  const trackingId = String(row.tracking_id ?? '').trim();
  if (!trackingId) return [];

  const correlationId = String(row.correlation_id ?? '').trim();
  const finalStatus = toFinalStatus(row);

  return [{
    json: {
      tracking_id: trackingId,
      correlation_id: correlationId,
      action: String(row.action ?? 'pause_ad'),
      run_mode: String(row.run_mode ?? 'manual'),
      status: finalStatus,
      final_status: finalStatus,
      result: finalStatus,
      Contrato_ID: String(row.Contrato_ID ?? row.target_contract_id ?? ''),
      Ad_ID: String(row.Ad_ID ?? row.target_ad_id ?? ''),
      precheck_status: String(row.ad_status_meta ?? row.precheck_status ?? 'UNKNOWN'),
      meta_http_status: Number(row.pause_status_code ?? row.precheck_status_code ?? row.http_status ?? 0) || null,
      pause_attempt: Number(row.pause_attempt ?? row.precheck_attempt ?? 0) || 0,
      pause_max_attempts: Number(row.pause_max_attempts ?? row.precheck_max_attempts ?? 0) || 0,
      pause_reason: String(row.pause_reason ?? row.precheck_reason ?? ''),
      source_workflow: 'contract-guard-daily-killswitch',
      execution_id: String($execution?.id ?? ''),
      requested_at: String(row.requested_at ?? row.request_ts ?? nowIso),
      updated_at: nowIso,
      timestamp: nowIso
    }
  }];
});

const input = $input.first().json ?? {};
const payload = input.payload ?? input;

const contrataId = String(payload.Contrato_ID ?? payload.contract_id ?? '').trim();
const adId       = String(payload.Ad_ID       ?? payload.ad_id       ?? '').trim();
const trackingId = String(payload.tracking_id ?? '').trim();
